clear
clc
%%
% СОЗДАНИЕ ОБЪЕКТА IF97 (свойства воды и пара)
javaaddpath if97.jar
unitSystem  =  javaMethod('valueOf', 'com.hummeling.if97.IF97$UnitSystem', 'ENGINEERING');
if97  =  com.hummeling.if97.IF97(unitSystem);
%%
%[text] единицы измерения величин:
%[text] ![](text:image:2032)
%%
%[text] ## Исходные данные
%[text] ![](text:image:5215)
t1_in = 310; % температура теплоносителя вход (t'1), °С
t1_out = 282; % температура теплоносителя в выход (t''1), °С
t_pv = 225; % темп-ра питательной воды (tпв), °С
D_pg = 320; % паропроизводительность (Dпг), кг/с
alpha_pr = 0.7; % расход непрерывной продувки (αпр), %
d_n = 16; % наружный диаметр труб ПТО (dн), мм
delta_tr = 1.5; %толщина труб ПТО (δтр), мм
d_kn = 1100; % наружный диаметр стенки коллекторов (dkн), мм
delta_k = 140; % толщина стенки коллекторов (δк), мм
%%
%[text] ## Тепловой расчет ПГ
%[text] ### 2.3.1 Теплофизические характеристики теплоносителя
dt_zap =20; % запас до кипения (Δtзап), °С %[control:slider:003d]{"position":[9,11]}
t1s = t1_in + dt_zap; % темп-ра насыщения (t1s), °С
p1 = if97.saturationPressureT(t1s); % давление при насыщении(p1), °С
t1_ = (t1_in + t1_out) / 2; % средняя темп-ра (t1_), °С 
rho1 = if97.densityPT(p1, t1_); % средняя плотность (ρ1), кг/м^3
mu1 = if97.dynamicViscosityPT(p1, t1_); % дин. вязкость (μ1), Па*с
nu1 = mu1 / rho1; % кин. вязкость (ν1), м^2/с
lambda1 = if97.thermalConductivityPT(p1, t1_); % средняя теплопроводность (λ1), кВт/(м*°С)
cp1 = if97.isobaricHeatCapacityPT(p1, t1_); % средняя теплоемкость (cp1), кДж/(кг*°С)
Pr1 = if97.PrandtlPT(p1, t1_); % число Прандтля

%вывод результата:
run out231.m %[output:58cf15b4]
%%
%[text] ### 2.3.2 Теплофизические характеристики рабочего тела
minHeating = 10; % минимальный температурный напор (δt), °С %[control:slider:04d7]{"position":[14,16]}
x2 = 0.998; % степень сухости генерируемого пара %[control:spinner:229d]{"position":[6,11]}

feedwaterTempSat = t1_out - minHeating; % температура насыщения рабочего тела в объеме ПГ (t2s), °С
feedwaterPres = if97.saturationPressureT(feedwaterTempSat); %давление рабочего тела (p2), бар
feedwaterEnthalpyIn = if97.specificEnthalpyPT(feedwaterPres, t_pv); % энтальпия питательной воды на входе в ПГ (hпв), кДж/кг
purgewaterEnthalpy = if97.specificEnthalpySaturatedLiquidP(feedwaterPres); % энтальпия продувочной воды (hпр = h'), кДж/кг
saturatedSteamEnthalpy = if97.specificEnthalpySaturatedVapourP(feedwaterPres); % энтальпия сухого насыщенного пара при давлении p2 (h''2), кДж/кг
feedwaterEnthalpyOut = saturatedSteamEnthalpy * x2 + purgewaterEnthalpy * (1 - x2); % энтальпия осушенного пара на выходе из ПГ (h2), кДж/кг
feedwaterVolumeOut = if97.specificVolumeSaturatedVapourP(feedwaterPres) * x2 + if97.specificVolumeSaturatedLiquidP(feedwaterPres) * (1 - x2); % удельный объём пара на выходе из ПГ (v2), м^3 /кг
feedwaterDensityOut = 1 / feedwaterVolumeOut; % плотность пара на выходе из ПГ (ρ2), кг/м3
feedwaterDensityIn = if97.densityPT(feedwaterPres, t_pv); % Плотность питательной воды на входе в ПГ (ρпв), кг/м3

%вывод результата:
run out232.m %[output:19883001]
%%
%[text] ### 2.3.3 Материальный и тепловой балансы ПГ
efficiency =0.985; % КПД ПГ (ηпг) %[control:slider:8cb2]{"position":[13,18]}

continiousBlow = alpha_pr * D_pg / 100; % Величина непрерывной продувки ПГ (Dпр), кг/с
feedwaterConsumption = D_pg + continiousBlow; % Расход питательной воды, подаваемой в ПГ (Dпв), кг/с 
feedwaterHeat = D_pg * (feedwaterEnthalpyOut - feedwaterEnthalpyIn) + continiousBlow * (purgewaterEnthalpy - feedwaterEnthalpyIn); % Количество теплоты, получаемое рабочим телом в ПГ (Q2), кВт
coolantHeat = feedwaterHeat / efficiency; % Количество теплоты, передаваемое теплоносителем в ПГ (Q1), кВт
coolantConsumption = coolantHeat / (cp1 * (t1_in - t1_out)); % Расход теплоносителя через трубную систему поверхности теплообмена ПГ (G1), кг/с

%вывод результата:
run out233.m %[output:4a492c0d]
%%
%[text] ### 2.3.4. Расчёт коэффициента теплопередачи
thermalResist = 3* 1e-5; % Термическое сопротивление (Rзагр), 10^-5 м^2*°C/Вт %[control:slider:1e96]{"position":[17,18]}


